INSERT INTO cities (name, slug, state_id, description, budget_per_day, how_to_reach, seo_title, seo_description, last_verified_date) VALUES
('Guwahati', 'guwahati', (SELECT id FROM states WHERE name = 'Assam'), 'Gateway to the North East, famous for Kamakhya Temple and the mighty Brahmaputra river.', 1500, 'Guwahati International Airport, Guwahati Railway Station.', 'Guwahati Travel Guide | Plan Your Trip to Assam', 'Explore Guwahati, the hub of North East India. Discover top attractions, temples, and river cruises.', CURRENT_DATE),
('Kaziranga', 'kaziranga', (SELECT id FROM states WHERE name = 'Assam'), 'UNESCO World Heritage site home to the one-horned rhinoceros and diverse wildlife.', 2000, '5 hours drive from Guwahati airport or railway station.', 'Explore Kaziranga National Park | One-Horned Rhino Safari', 'Plan your wildlife adventure at Kaziranga. Best time to visit, safari timings, and stay guide.', CURRENT_DATE),
('Majuli Island', 'majuli-island', (SELECT id FROM states WHERE name = 'Assam'), 'Largest river island in the world and the cultural capital of Assam.', 1200, 'Ferry from Nimati Ghat near Jorhat.', 'Majuli Island Guide | World''s Largest River Island', 'Discover the unique Neo-Vaishnavite culture and satras of Majuli Island, Assam.', CURRENT_DATE),
('Tezpur', 'tezpur', (SELECT id FROM states WHERE name = 'Assam'), 'The City of Eternal Romance with a deep-rooted history in mythology.', 1000, '3.5 hours drive from Guwahati.', 'Tezpur Travel Guide | The Cultural Capital of Assam', 'Explore the historical monuments and scenic beauty of Tezpur, Assam.', CURRENT_DATE),
('Haflong', 'haflong', (SELECT id FROM states WHERE name = 'Assam'), 'The only hill station in Assam, known for its scenic views and diverse tribes.', 1000, 'Haflong Railway Station (well connected via Vistadome).', 'Haflong Hill Station Guide | Secret Gem of Assam', 'Discover the breathtaking hills and lakes of Haflong, the only hill station in Assam.', CURRENT_DATE),
('Sivasagar', 'sivasagar', (SELECT id FROM states WHERE name = 'Assam'), 'The historical seat of the Ahom Kingdom with majestic temples and palaces.', 900, 'Night bus or train from Guwahati to Sivasagar station.', 'Sivasagar Historical Guide | Ahom Kingdom Heritage', 'Visit the ancient capital of the Ahom dynasty. Explore Shiva Dol and Rang Ghar.', CURRENT_DATE);
INSERT INTO cities (name, slug, state_id, description, budget_per_day, how_to_reach, seo_title, seo_description, last_verified_date) VALUES
('Tawang', 'tawang', (SELECT id FROM states WHERE name = 'Arunachal Pradesh'), 'High-altitude town known for its massive monastery and breathtaking Sela Pass.', 2500, 'Shared taxi or private car from Guwahati/Tezpur (12-14 hours).', 'Tawang Travel Guide | Monastery and Mountains', 'Explore Tawang: Land of the Monpa people, ancient monasteries, and serene lakes.', CURRENT_DATE),
('Ziro Valley', 'ziro-valley', (SELECT id FROM states WHERE name = 'Arunachal Pradesh'), 'A picturesque valley home to the Apatani tribe and the famous Ziro Music Festival.', 1500, 'Train to Naharlagun, then 4 hours drive.', 'Ziro Valley Guide | Home of the Apatani Tribe', 'Visit Ziro for its unique culture, lush green valleys, and world-class music festival.', CURRENT_DATE),
('Bomdila', 'bomdila', (SELECT id FROM states WHERE name = 'Arunachal Pradesh'), 'A serene town offering panoramic views of the Himalayas and ancient monasteries.', 1500, '8 hours drive from Guwahati.', 'Bomdila Travel Guide | Gateway to Tawang', 'Plan your stay in Bomdila. Discover viewpoints, monasteries, and apple orchards.', CURRENT_DATE),
('Dirang', 'dirang', (SELECT id FROM states WHERE name = 'Arunachal Pradesh'), 'A beautiful valley known for its hot springs, apple orchards, and old fort (Dzong).', 1200, '7 hours drive from Guwahati.', 'Dirang Valley Guide | Hot Springs and Orchards', 'Explore Dirang, a peaceful stopover on the way to Tawang with unique culture.', CURRENT_DATE),
('Pasighat', 'pasighat', (SELECT id FROM states WHERE name = 'Arunachal Pradesh'), 'The oldest town in Arunachal, situated on the banks of the Siang River.', 1500, 'Bus or taxi from Itanagar or Dibrugarh via ferry.', 'Pasighat Guide | The Gateway of Arunachal', 'Discover Pasighat, the oldest town on the Siang river bank. Best for rafting.', CURRENT_DATE),
('Itanagar', 'itanagar', (SELECT id FROM states WHERE name = 'Arunachal Pradesh'), 'The capital city known for the Ita Fort and the Gekar Sinyi (Ganga Lake).', 1500, 'Flight to Hollongi Airport or train to Naharlagun.', 'Itanagar Capital Guide | History and Nature', 'Visit the capital of Arunachal Pradesh. Explore Ita Fort and Buddhist monasteries.', CURRENT_DATE);
