('Kohima', 'kohima', (SELECT id FROM states WHERE name = 'Nagaland'), 'Hill capital town, famous for the Hornbill Festival and World War II history.', 1500, '2.5 hours drive from Dimapur railway station.', 'Kohima Travel Guide | Hornbill Festival Capital', 'Explore Kohima: History of the Nagas, WWII Cemetery, and the famous festivals.', CURRENT_DATE),
('Dimapur', 'dimapur', (SELECT id FROM states WHERE name = 'Nagaland'), 'The commercial hub and entry point of Nagaland, home to Kachari ruins.', 1200, 'Well connected by air and rail to Guwahati and Kolkata.', 'Dimapur Travel Guide | Gateway to Nagaland', 'Discover Dimapur heritage, its ancient Kachari ruins, and bustling markets.', CURRENT_DATE),
('Mon', 'mon', (SELECT id FROM states WHERE name = 'Nagaland'), 'Home of the Konyak Nagas, famous for their facial tattoos and wood carvings.', 1500, 'Bus or taxi from Dibrugarh or Jorhat (Assam).', 'Mon Nagaland Guide | Konyak Tribe Heritage', 'Visit the land of the Konyaks. Explore tribal heritage, tattoos, and longhouses.', CURRENT_DATE),
('Mokokchung', 'mokokchung', (SELECT id FROM states WHERE name = 'Nagaland'), 'Cultural center of the Ao Nagas, known for its vibrant festivals and traditions.', 1200, '6 hours drive from Jorhat, Assam.', 'Mokokchung Guide | Ao Naga Cultural Center', 'Explore Mokokchung: the pulse of Ao Naga traditions and beautiful hill scenery.', CURRENT_DATE);
INSERT INTO cities (name, slug, state_id, description, budget_per_day, how_to_reach, seo_title, seo_description, last_verified_date) VALUES
('Gangtok', 'gangtok', (SELECT id FROM states WHERE name = 'Sikkim'), 'The vibrant capital known for its MG Road, monasteries, and views of Kanchenjunga.', 2000, '4 hours drive from Bagdogra airport or NJP station.', 'Gangtok Travel Guide | Explore the Capital of Sikkim', 'Discover Gangtok: monasteries, cable cars, and the best views of the Himalayas.', CURRENT_DATE),
('Pelling', 'pelling', (SELECT id FROM states WHERE name = 'Sikkim'), 'A peaceful town offering the closest views of Mount Kanchenjunga.', 1800, '5 hours drive from Gangtok or Siliguri.', 'Pelling Travel Guide | Closest Kanchenjunga Views', 'Visit Pelling for its Skywalk, ancient monasteries, and lush waterfalls.', CURRENT_DATE),
('Lachung', 'lachung', (SELECT id FROM states WHERE name = 'Sikkim'), 'A high-altitude village that serves as the gateway to Yumthang Valley.', 2500, '6 hours drive from Gangtok.', 'Lachung Travel Guide | Gateway to Yumthang Valley', 'Explore North Sikkim from Lachung. Tips for visiting Yumthang and Zero Point.', CURRENT_DATE),
('Lachen', 'lachen', (SELECT id FROM states WHERE name = 'Sikkim'), 'Base for Gurudongmar Lake, one of the highest and most sacred lakes.', 2500, '6 hours drive from Gangtok.', 'Lachen Travel Guide | Base for Gurudongmar Lake', 'Plan your visit to North Sikkim from Lachen. Permits and logistics guide.', CURRENT_DATE),
('Namchi', 'namchi', (SELECT id FROM states WHERE name = 'Sikkim'), 'The religious hub of Sikkim, famous for the Samdruptse Hill and Char Dham.', 1500, '3 hours drive from Gangtok.', 'Namchi South Sikkim Guide | Religious and Scenic', 'Discover the massive statues and spiritual legacy of Namchi, South Sikkim.', CURRENT_DATE),
('Yuksom', 'yuksom', (SELECT id FROM states WHERE name = 'Sikkim'), 'The first capital of Sikkim and the base for the Goechala Trek.', 1500, '5 hours drive from Siliguri.', 'Yuksom Guide | Gateway to Kanchenjunga National Park', 'Visit the historic first capital. Base for Sikkim''s best trekking routes.', CURRENT_DATE);
